#!/usr/bin/env node
/**
 * PreToolUse scope guard for 系统模式 (UI-update) headless claude runs — cwd is the CODE repo.
 * Registered via {data}/state/settings.system.json (generated by the server). DENIES:
 *   - Edit/Write/MultiEdit/NotebookEdit outside `src/client/`
 *   - Bash that mutates git history or destroys files (the SERVER builds; the human commits)
 *   - Bash filesystem crawling (dir / find / ls -R) — use Read/Glob/Grep
 * Anything else: silent exit 0 (normal acceptEdits flow proceeds).
 */
import path from 'node:path';

const ALLOWED_DIRS = ['src/client'];

const FORBIDDEN_BASH = [
  /\bgit\s+commit\b/, /\bgit\s+add\b/, /\bgit\s+push\b/, /\bgit\s+reset\b/,
  /\bgit\s+restore\b/, /\bgit\s+checkout\b/, /\bgit\s+clean\b/, /\bgit\s+rebase\b/,
  /\bgit\s+stash\b/, /\bgit\s+rm\b/, /\brm\s+-[rf]/, /\bRemove-Item\b/i,
];
const CRAWL = [/(^|[\s;&|(])dir(\s|$)/i, /(^|[\s;&|(])find\s/, /(^|[\s;&|(])ls\s+-[a-zA-Z]*[Rr]/];

function deny(reason) {
  process.stdout.write(JSON.stringify({
    hookSpecificOutput: { hookEventName: 'PreToolUse', permissionDecision: 'deny', permissionDecisionReason: reason },
  }));
  process.exit(0);
}
const allow = () => process.exit(0);

const chunks = [];
for await (const c of process.stdin) chunks.push(c);
let payload;
try { payload = JSON.parse(Buffer.concat(chunks).toString('utf8') || '{}'); } catch { allow(); }

const toolName = payload.tool_name ?? '';
const toolInput = payload.tool_input ?? {};
const projectDir = payload.cwd || process.env.CLAUDE_PROJECT_DIR || process.cwd();

if (toolName === 'Bash') {
  const command = String(toolInput.command ?? '');
  const hit = FORBIDDEN_BASH.find((re) => re.test(command));
  if (hit) deny(`Blocked: no git-history / destructive commands in 系统模式 (matched ${hit}). The server commits after diff approval.`);
  if (CRAWL.some((re) => re.test(command)))
    deny('Blocked: use Read / Glob / Grep to find code — not Bash crawling (dir / find / ls -R).');
  allow();
}

if (['Edit', 'Write', 'MultiEdit', 'NotebookEdit'].includes(toolName)) {
  const filePath = toolInput.file_path ?? toolInput.notebook_path ?? toolInput.path ?? '';
  if (!filePath) allow();
  const abs = path.isAbsolute(filePath) ? filePath : path.resolve(projectDir, filePath);
  const rel = path.relative(projectDir, abs).split(path.sep).join('/');
  if (rel.startsWith('..') || path.isAbsolute(rel)) deny(`Blocked: ${filePath} is outside the repo.`);
  if (!ALLOWED_DIRS.some((d) => rel === d || rel.startsWith(d + '/')))
    deny(`Blocked: 系统模式 may only edit ${ALLOWED_DIRS.join(', ')} — not "${rel}".`);
  allow();
}

allow();
